+    fn test_version_equality() {
+        let v1 = Version::parse("1.2.3").unwrap();
+        let v2 = Version::parse("1.2.3").unwrap();
+        assert_eq!(v1, v2);
+
+        let v3 = Version::parse("v1.2.3").unwrap();
